-- Generated automatically from whitelist/community.csv
-- Source of truth sync: upsert current emails, disable missing ones

begin;

create temp table tmp_whitelist (
  email text primary key
) on commit drop;


select t.email, true, true, 'csv_sync', now()
from tmp_whitelist t
on conflict (email) do update set
  can_register = excluded.can_register,
  can_login = excluded.can_login,
  source = excluded.source,
  last_synced_at = excluded.last_synced_at;

update public.auth_whitelist w
set
  can_register = false,
  can_login = false,
  source = 'csv_sync',
  last_synced_at = now()
where not exists (
  select 1
  from tmp_whitelist t
  where t.email = w.email
);

commit;
